mapper.select:
select sl.id, s.name as student_name, u.mobile, l.title as course, l.date, l.start_time, l.end_time, st.name as teacher_names, sl.reason, sl.add_time, sl.state as state_code, case sl.state when 1 then '请假中' when 2 then '已撤销' end as state from student_leave sl join student s on sl.student_id = s.id join user u on s.user_id = u.id join lesson l on sl.lesson_id = l.id join staff st on l.teacher_id = st.id
AND ( s.name LIKE CONCAT('%', #{query.nameOrPhone}, '%') OR u.mobile LIKE CONCAT('%', #{query.nameOrPhone}, '%') )
and l.teacher_id = #{query.teacherId}
and sl.add_time >= #{query.startDate}
and sl.add_time <= #{query.endDate}
order by sl.add_time desc
